+func TestRigConfigValidation(t *testing.T) {
+	tests := []struct {
+		name    string
+		config  *RigConfig
+		wantErr bool
+	}{
+		{
+			name: "valid config",
+			config: &RigConfig{
+				Type:       "rig",
+				Version:    1,
+				MergeQueue: DefaultMergeQueueConfig(),
+			},
+			wantErr: false,
+		},
+		{
+			name: "valid config without merge queue",
+			config: &RigConfig{
+				Type:    "rig",
+				Version: 1,
+			},
+			wantErr: false,
+		},
+		{
+			name: "wrong type",
+			config: &RigConfig{
+				Type:    "wrong",
+				Version: 1,
+			},
+			wantErr: true,
+		},
+		{
+			name: "invalid on_conflict",
+			config: &RigConfig{
+				Type:    "rig",
+				Version: 1,
+				MergeQueue: &MergeQueueConfig{
+					OnConflict: "invalid",
+				},
+			},
+			wantErr: true,
+		},
+		{
+			name: "invalid poll_interval",
+			config: &RigConfig{
+				Type:    "rig",
+				Version: 1,
+				MergeQueue: &MergeQueueConfig{
+					PollInterval: "not-a-duration",
+				},
+			},
+			wantErr: true,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			err := validateRigConfig(tt.config)
+			if (err != nil) != tt.wantErr {
+				t.Errorf("validateRigConfig() error = %v, wantErr %v", err, tt.wantErr)
+			}
+		})
+	}
+}
